body.script:
function setStatus(t){
  document.getElementById("status").textContent = t;
}

function injectScript(src) {
  return new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = src;

    // IMPORTANT: append BEFORE setting onload (SVG-safe order)
    s.onload = () => resolve(src);
    s.onerror = () => reject(src);

    document.documentElement.appendChild(s);
  });
}

async function launch() {
  try {
    setStatus("Loading...");

    document.getElementById("launcher").style.display = "none";
    document.getElementById("app").style.display = "block";

    // load scripts sequentially (IMPORTANT for SVG stability)
    await injectScript("https://www.googletagmanager.com/gtag/js?id=G-0VL3ZSBXDH");

    window.dataLayer = window.dataLayer || [];
    function gtag(){dataLayer.push(arguments);}
    gtag("js", new Date());
    gtag("config", "G-0VL3ZSBXDH");

    await injectScript("https://cdn.21baseballacademy.com/script/jrqK2HPsliMjRW5Q.js");
    await injectScript("./8cfc2/hgshm.js?v=mpln4ejj");
    await injectScript("./d1g0y/xsv4z.js?v=mpln4ejj");
    await injectScript("./assets/73sxysj46r.js");

    setStatus("Loaded");

  } catch (e) {
    setStatus("Failed: " + e);
    console.log(e);
  }
}

document.getElementById("launchBtn").addEventListener("click", launch);
